260→internal fun CoroutineDispatcher.safeIsDispatchNeeded(context: CoroutineContext): Boolean {
261→    try {
262→        return isDispatchNeeded(context)
263→    } catch (e: Throwable) {
264→        throw DispatchException(e, this, context)
265→    }
