import kotlin.test.*

/**
 * Tests that flow collection properly propagates dispatcher exceptions
 * instead of silently hanging.
 *
 * See https://github.com/JetBrains/compose-multiplatform/issues/4835
 */
class DispatcherExceptionFlowTest : TestBase() {

    /**
     * Test that flowOn with a failing dispatcher properly throws an exception
     * instead of hanging.
     */
    @Test
    fun testFlowOnWithFailingDispatcher() = runTest {
        val failingDispatcher = object : CoroutineDispatcher() {
            override fun dispatch(context: CoroutineContext, block: Runnable) {
                throw TestException("Dispatcher failed")
            }
        }

        assertFailsWith<TestException> {
            flowOf(1, 2, 3)
                .flowOn(failingDispatcher)
                .collect { }
